// // This is a 5-bit binary counter with an active-low synchronous reset. It counts from 31 down to 0 and then wraps around.
module top_module(
    input clk,
    input reset,
    output reg [4:0] q);always @(posedge clk) begin
    if (reset)
        q <= 5'b00000;
    else
        q <= q + 1'b1;
end
endmodule
